const body = $input.first().json.body || $input.first().json;
const agent_id = (body.agent_id || '').toLowerCase().trim();
const message = body.message || '';
const user_id = body.user_id || null;
const org_id = body.org_id || null;
const session_id = body.session_id || crypto.randomUUID();

const VALID_AGENTS = ['growth', 'offer', 'sales', 'content', 'automation', 'finance'];
if (!message.trim()) throw new Error('message is required');
if (!user_id) throw new Error('user_id is required');
if (!VALID_AGENTS.includes(agent_id)) throw new Error(`Invalid agent_id. Must be one of: ${VALID_AGENTS.join(', ')}`);

return [{ json: { agent_id, message, user_id, org_id, session_id, now: new Date().toISOString() } }];

