const aiResp = $input.first().json;
const ctx = $('Parse Request').item.json;
const content = aiResp?.choices?.[0]?.message?.content || aiResp?.error?.message || 'No response received.';
return [{ json: { success: true, response: content, agent_id: ctx.agent_id, session_id: ctx.session_id } }];

const err = $input.first().json;
const errorMessage = err?.message || err?.error || 'An unexpected error occurred.';
return [{ json: { success: false, error: errorMessage } }];
